const ports = [];

onconnect = (e) => {
  const port = e.ports[0];
  ports.push(port);
  port.start();

  port.onmessage = (event) => {
    // Рассылаем сообщение всем подключённым вкладкам
    for (const p of ports) {
      p.postMessage(`От вкладки: ${event.data}`);
